        }

        if (email_exists($email)) {
            $this->redirect_with_error('Email already exists.');
        }

        $user_id = wp_create_user($username, wp_generate_password(32, true, true), $email);

        if (is_wp_error($user_id)) {
            $this->redirect_with_error($user_id->get_error_message());
        }

        $password_hash = password_hash($password, PASSWORD_DEFAULT);
        update_user_meta($user_id, self::META_PASSWORD_HASH, $password_hash);

        wp_safe_redirect(add_query_arg('sua_registered', '1', $this->get_redirect_url()));
        exit;
    }

    public function handle_login_submission()
    {
        if ($_SERVER['REQUEST_METHOD'] !== 'POST') {
            return;
