        }

        $identifier = isset($_POST['sua_login_username']) ? sanitize_text_field(wp_unslash($_POST['sua_login_username'])) : '';
        $password = isset($_POST['sua_login_password']) ? (string) wp_unslash($_POST['sua_login_password']) : '';

        if (empty($identifier) || empty($password)) {
            $this->redirect_with_login_error('Username/email and password are required.');
        }

        $user = $this->get_user_by_identifier($identifier);

        if (!$user) {
            $this->redirect_with_login_error('Invalid credentials.');
        }

        $stored_hash = get_user_meta($user->ID, self::META_PASSWORD_HASH, true);

        if (empty($stored_hash) || !password_verify($password, $stored_hash)) {
